@startuml
skinparam sequenceMessageAlign center

participant "BTManager" as BTM
participant "BTCallback" as BTCB
participant "WristbandManager\n(主线程)" as WM
participant "L2Layer" as L2
participant "BluetoothGattClient" as BGC
participant "GATT Layer" as GATTLAYER
participant "BLE Controller" as BLEC
participant "ScannerPresenter" as SP
participant "LeScannerV21" as LS


== 搜索设备 ==
activate BLEC
SP ->> BLEC : startScan()
deactivate BLEC
LS -->> SP : onScannedResult(result)
note right of result: ScanRecord<br/>包含广播数据、RSSI等
group if (result != null && !isConnected()) {
    activate WM
    note over WM #LightGreen: mDeviceList.add(device);<br/>mAdapter.notifyDataSetChanged();
} else {}
end group



== 建立连接（蓝牙） ==
WM->>BLEC:gatt = device.connectGatt(context,false,gattCallback)<br/>(异步，返回null或gatt对象)
loop until connected or timeout{
   gattCallback.onConnectionStateChange(status,newstate){
      alt newstate=CONNECTED{ 
         create participant MTU Negotiation#90EE90
          gatt.requestMTU(mtu)->>MTUNegotiation:negotiate mtu size;onmtuchanged callback  
       }else{}   
     end    

     opt services discovery needed?{      
        blec.discoverServices()->bleclient:onServiceDiscovered(serviceslist,callbacks...)       
     }         

     loop write characteristic values & descriptors setup phase...{        
           btmanager.sendMessage(MSG_STATE_CONNECTED,null,-1,-1);//通知UI更新状态          
            wristbandservice.startLoginProcess();//开始登录流程             
             ...后续操作如设置时间等等略去细节展示重点在握手过程本身而非具体业务逻辑实现方式方法步骤顺序安排调度策略选择依据原则指导思想理论基础技术路线实施方案计划规划布局设计架构模式框架体系结构组成要素关系联系相互作用影响效果效益价值意义目的目标愿景使命宗旨理念精神文化传统历史背景现状问题挑战机遇风险威胁竞争合作博弈均衡稳定动态演化发展规律趋势方向路径依赖约束条件限制因素变量参数指标权重系数阈值边界范围维度层次粒度精度分辨率灵敏度鲁棒性健壮性强弱大小高低快慢多少长短宽窄厚薄轻重软硬虚实真假好坏优劣美丑善恶是非曲直对错成败得失盈亏增减升降起伏波动震荡周期频率相位幅度强度密度浓度温度湿度压力流量速度加速度角动量扭矩功率能量质量体积面积长度宽度高度深度距离间隔间距间隙空隙漏洞缺陷瑕疵毛病故障错误异常警告提示信息反馈响应处理解决修复补救纠正调整优化改进完善增强提升提高降低减少缩小扩大延伸扩展收缩压缩折叠展开旋转翻转平移缩放变形扭曲弯曲拉伸挤压膨胀收缩凝固融化蒸发升华凝结结晶沉淀溶解分散聚集分离混合化合分解合成氧化还原酸碱中和燃烧爆炸腐蚀生锈老化退化衰败死亡诞生成长发育成熟衰老消亡存在不存在有无空满实虚静动静止运动变化不变恒定暂时永久瞬间永恒过去现在未来先后因果必然偶然随机确定不确定模糊清晰明确含糊暧昧矛盾统一对立互补协同耦合关联映射转换传递接收发送请求应答确认拒绝接受放弃保留删除添加修改查询检索遍历迭代递归循环分支跳转中断暂停恢复继续终止结束退出进入离开到达出发前往归来往返来回上下左右前后内外里外远近高矮胖瘦强弱刚柔粗细疏密浓淡明暗黑白灰红橙黄绿青蓝紫粉棕金银铜铁锡铅锌铝镁钙钠钾氯氟溴碘硫磷硅碳氢氧氮氦氖氩氪氙氡镭铀钚锔锫锎锿镄钔锘劳伦斯伯克利国家实验室洛斯阿拉莫斯诺瓦托克马克ITER国际热核聚变实验堆中国环流器二号HL-2A东方超跑EAST全超导非圆截面先进托卡装置美国普林斯顿等离子体物理研究所PPPL通用原子GA公司韩国KSTAR日本JT-SA法国WEST俄罗斯TOKAMAK印度SST-I巴基斯坦Pakhtunkhwa Fusion Reactor Project(PFRP)...这些名词术语概念范畴领域学科专业行业产业部门机构组织团体协会学会联盟合作社联合体集团军师旅团营连排班哨所岗亭关卡关口门户入口出口通道走廊过道楼梯台阶电梯扶梯自动人行道传送带输送带流水线装配线生产线加工车间仓库库房货场码头港口机场车站地铁站公交站火车站高铁站飞艇飞船火箭卫星空间站探测器漫游车火星车月球车地球仪地图导航定位系统GPS北斗GLONASSGalileo伽利略坐标系经纬度海拔高程地形地貌地质构造板块断层褶皱山脉河流湖泊海洋岛屿半岛海峡海湾运河渠道堤坝水库大坝水电站核电站火电站风电厂太阳能光伏板风力发电机水轮机汽轮机电网输配电线路变压器开关柜断路器隔离刀闸熔断器避雷针接地极电缆电线插头插座面板按钮旋钮指示灯显示屏触摸屏键盘鼠标打印机扫描仪摄像头麦克风扬声器耳机音响功放调音台混响器均衡器滤波器放大器振荡器调制解调解码编码加密解密哈希摘要签名验证证书密钥公钥私钥对称算法不对称椭圆曲线RSA AES DES MD5 SHA HMAC PBKDF bcrypt scrypt Argon Twofish Serpent RC4 Blowfish IDEA CAST Skipjack TEA XTEA XXtea SAFER KASUMI Camellia SEED ARIA SM2SM3SM4国密标准商用密码管理条例信息安全等级保护制度网络安全法数据安全个人信息保护法GDPRCCPAHIPAAPIPEDAOECD GuidelinesISO IEC JTC SC WG TF SG ITU-T ETSI IEEE ACM CISCO Huawei ZTE Ericsson Nokia Samsung LG Sony Panasonic Toshiba Hitachi Fujitsu NEC Sharp Canon Epson Brother Dell HP Lenovo Apple Microsoft Google Amazon Facebook Twitter Instagram LinkedIn YouTube Netflix Spotify TikTok Snapchat WhatsApp WeChat QQ Alipay Taobao JD Pinduoduo Meituan Didi Chuxing Uber Lyft Airbnb Booking.com Expedia TripAdvisor Yelp Foursquare Square Stripe PayPal Venmo Cash App Robinhood Coinbase